code.Python3:
import sys
def solve():
    data=sys.stdin.buffer.read().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        N=int(next(it)); X=int(next(it))
        found=False
        for _ in range(N):
            if int(next(it))==X:
                found=True
        out.append('YES' if found else 'NO')
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    solve()

