const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=Number(input[idx++]);
let res=[];
for(let t=0;t<T;++t){
  const N=Number(input[idx++]);
  const X=Number(input[idx++]);
  let found=false;
  for(let i=0;i<N;++i){
    const v=Number(input[idx++]);
    if(v===X) found=true;
  }
  res.push(found?'YES':'NO');
}
